export const EnvData = (
  name: string,
  port: number,
  baseUrl: string,
  appKey: string,
  databaseNormalized: string,
  dbLines: string[]
): string[] => [
  ...HeaderAndApp(name, port, baseUrl, appKey),
  ...SecurityAndDeployment(),
  ...DatabaseAndCloudflare(databaseNormalized, dbLines),
  ...HttpProxies(),
  ...CacheAndRedis(),
  ...QueueConfig(),
  ...WorkersSchedulingAndSSE(),
  ...LoggingAndMail(),
  ...StorageAndBroadcast(),
  ...NotificationsAndObservability(),
];
